// POST /api/:collection/distinct - Get distinct values for a field
app.post('/api/:collection/distinct', async (req, res) => {
  try {
    const { collection } = req.params;
    const { field, filter = {} } = req.body;

    if (!field || typeof field !== 'string') {
      return res.status(400).json({
        success: false,
        error: 'A "field" string is required'
      });
    }

    const sanitizedFilter = sanitizeFilter(filter);
    const convertedFilter = convertTypes(sanitizedFilter);

    const values = await db.collection(collection).distinct(field, convertedFilter);

    res.json({
      success: true,
      data: values,
      count: values.length
    });
  } catch (error) {
    console.error('Distinct error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

// POST /api/:collection/aggregate - Run aggregation pipelines
app.post('/api/:collection/aggregate', async (req, res) => {
  try {
    const { collection } = req.params;
    const { pipeline = [] } = req.body;

    if (!Array.isArray(pipeline)) {
      return res.status(400).json({
        success: false,
        error: 'Pipeline must be an array'
      });
    }

    // Sanitize each stage's match filters if present
    const sanitizedPipeline = pipeline.map(stage => {
      if (stage.$match) {
        return { ...stage, $match: sanitizeFilter(stage.$match) };
      }
      // Block $out and $merge to prevent writing
      if (stage.$out || stage.$merge) {
        throw new Error('$out and $merge stages are not allowed');
      }
      return stage;
    });

    const results = await db.collection(collection).aggregate(sanitizedPipeline).toArray();

    res.json({
      success: true,
      data: results,
      count: results.length
    });
  } catch (error) {
    console.error('Aggregate error:', error.message);
    res.status(400).json({
      success: false,
      error: error.message
    });
  }
});

